        pad_d_left_  = p.pad_d_left;
        pad_d_right_ = p.pad_d_right;
        pad_h_left_  = p.pad_h_left;
        pad_h_right_ = p.pad_h_right;
        pad_w_left_  = p.pad_w_left;
        pad_w_right_ = p.pad_w_right;

        const ck_tile::index_t Zs = (Z_ - 1) * dilation_d_ + 1;
