    const bool kernel_is_overlap = SelectedKernel::kHasOverlap;
    const bool problem_overlap   = ((Z_ - 1) * dilation_d_ + 1) > stride_d_ ||
                                 ((Y_ - 1) * dilation_h_ + 1) > stride_h_ ||
                                 ((X_ - 1) * dilation_w_ + 1) > stride_w_;
